import { Component, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../../data/seed.service';
import { AuthService } from '../../../core/services/auth.service';
import { Order, PortalRequest, PortalNotification } from '../../../data/models';

@Component({
  selector: 'app-portal-dashboard',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './portal-dashboard.component.html',
  styleUrl: './portal-dashboard.component.css',
})
export class PortalDashboardComponent {
  // STRICT company scoping — QES data only.
  orders = computed<Order[]>(() =>
    this.seed.orders().filter((o) => o.accountName.includes('QES')),
  );
  requests = computed<PortalRequest[]>(() => this.seed.portalRequests());
  notifications = computed<PortalNotification[]>(() => this.seed.portalNotifications());

  openOrders = computed(() => this.orders().filter((o) => o.status !== 'delivered'));
  onTrack = computed(() => this.orders().filter((o) => !o.slippage));
  delayed = computed(() => this.orders().filter((o) => o.slippage));
  openRequests = computed(() => this.requests().filter((r) => r.status !== 'accepted'));
  unread = computed(() => this.notifications().filter((n) => !n.read));

  recentOrders = computed(() => this.orders().slice(0, 3));
  recentRequests = computed(() => this.requests().slice(0, 4));
  recentNotifications = computed(() => this.notifications().slice(0, 4));

  constructor(public seed: SeedService, public auth: AuthService) {}

  deliveryBadge(o: Order): { cls: string; label: string } {
    return o.slippage
      ? { cls: 'badge-warning', label: `Delayed ${o.slippageDays}d` }
      : { cls: 'badge-success', label: 'On time' };
  }

  requestBadge(status: PortalRequest['status']): string {
    switch (status) {
      case 'submitted': return 'badge-info';
      case 'in-review': return 'badge-warning';
      case 'quoted': return 'badge-success';
      case 'accepted': return 'badge-success';
      default: return 'badge-neutral';
    }
  }
}
